    static int[] parent;

    static void init(int n) {
        parent = new int[n];
        for (int i = 0; i < n; i++) parent[i] = i;
    }

    static int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    static boolean union(int a, int b) {
        int rootA = find(a);
        int rootB = find(b);
        if (rootA == rootB) {
            return false; // already connected -- this edge would create a CYCLE
        }
        parent[rootA] = rootB;
        return true;
    }

    static boolean hasCycle(int[][] edges, int n) {
        init(n);
        for (int[] edge : edges) {
            if (!union(edge[0], edge[1])) {
                return true; // this edge connects two ALREADY-connected nodes
            }
        }
        return false;
    }

    public static void main(String[] args) {
        int[][] edges = {{0, 1}, {1, 2}, {2, 0}}; // 0-1-2-0 forms a cycle
        System.out.println(hasCycle(edges, 3));
    }
}

