class Solution {
    private int[] parent;

    public int[] findRedundantConnection(int[][] edges) {
        int n = edges.length;
        parent = new int[n + 1];
        for (int i = 0; i <= n; i++) parent[i] = i;

        for (int[] edge : edges) {
            int rootA = find(edge[0]);
            int rootB = find(edge[1]);
            if (rootA == rootB) return edge;
            parent[rootA] = rootB;
        }
        return new int[0];
    }

    private int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }
}

class Solution {
    private Map<Integer, Integer> parent = new HashMap<>();

    public List<List<String>> accountsMerge(List<List<String>> accounts) {
        Map<String, Integer> emailId = new HashMap<>();
        Map<String, String> emailToName = new HashMap<>();
        int id = 0;
        for (List<String> account : accounts) {
            String name = account.get(0);
            for (int i = 1; i < account.size(); i++) {
                String email = account.get(i);
                if (!emailId.containsKey(email)) {
                    emailId.put(email, id++);
                    parent.put(emailId.get(email), emailId.get(email));
                }
                emailToName.put(email, name);
                union(emailId.get(account.get(1)), emailId.get(email));
            }
        }

        Map<Integer, TreeSet<String>> groups = new HashMap<>();
        for (String email : emailId.keySet()) {
            int root = find(emailId.get(email));
            groups.computeIfAbsent(root, k -> new TreeSet<>()).add(email);
        }

        List<List<String>> result = new ArrayList<>();
        for (TreeSet<String> emails : groups.values()) {
            List<String> merged = new ArrayList<>();
            merged.add(emailToName.get(emails.first()));
            merged.addAll(emails);
            result.add(merged);
        }
        return result;
    }

    private int find(int x) {
        if (parent.get(x) != x) parent.put(x, find(parent.get(x)));
        return parent.get(x);
    }

    private void union(int a, int b) {
        int rootA = find(a), rootB = find(b);
        if (rootA != rootB) parent.put(rootA, rootB);
    }
}

class Solution {
    private int[] parent;

    public int makeConnected(int n, int[][] connections) {
        if (connections.length < n - 1) return -1;
        parent = new int[n];
        for (int i = 0; i < n; i++) parent[i] = i;
        for (int[] c : connections) {
            union(c[0], c[1]);
        }
        int components = 0;
        for (int i = 0; i < n; i++) {
            if (find(i) == i) components++;
        }
        return components - 1;
    }

    private int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }

    private void union(int a, int b) {
        int rootA = find(a), rootB = find(b);
        if (rootA != rootB) parent[rootA] = rootB;
    }
}

class Solution {
    private int[] parent;

    public int minCostConnectPoints(int[][] points) {
        int n = points.length;
        List<int[]> edges = new ArrayList<>(); // {cost, i, j}
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int cost = Math.abs(points[i][0] - points[j][0]) + Math.abs(points[i][1] - points[j][1]);
                edges.add(new int[]{cost, i, j});
            }
        }
        edges.sort((a, b) -> a[0] - b[0]);

        parent = new int[n];
        for (int i = 0; i < n; i++) parent[i] = i;

        int totalCost = 0, edgesUsed = 0;
        for (int[] edge : edges) {
            int rootA = find(edge[1]), rootB = find(edge[2]);
            if (rootA != rootB) {
                parent[rootA] = rootB;
                totalCost += edge[0];
                edgesUsed++;
                if (edgesUsed == n - 1) break;
            }
        }
        return totalCost;
    }

    private int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }
}

